def decompose_and_verify(task, agent, verify_claim, llm):
    """Scalable oversight by decomposition: check sub-claims, not the whole output."""
    solution = agent.solve(task)
    claims = llm(f"List the key factual/logical claims this solution depends on:\n"
                 f"{solution}").splitlines()
    results = []
    for claim in claims:
        if not claim.strip():
            continue
        ok = verify_claim(claim)          # human or a cheaper checker per claim
        results.append((claim, ok))
    trustworthy = all(ok for _, ok in results)
    return {"solution": solution, "claims": results, "accept": trustworthy}

def debate_oversight(question, agent_a, agent_b, judge, rounds=3):
    """Two agents argue opposite answers; a limited judge rules on the transcript."""
    transcript = []
    for _ in range(rounds):
        transcript.append(("A", agent_a.argue(question, transcript)))
        transcript.append(("B", agent_b.argue(question, transcript)))
    # The judge need only evaluate the arguments, not solve the problem itself.
    return judge.rule(question, transcript)
